import React, { useState } from 'react';
import './style.css';
//import ReactDOM from 'react-dom/client';
//import reportWebVitals from './reportWebVitals';
const [selectedExercise,setSelectedExercise]=useState("red");
var index=0;
var value="";
function addExercise(){
    //e.preventDefault();

    console.log("exercise");
}

function SelectOption(props){
    return(
        <div id={props.index}>
            <form onSubmit={addExercise}>
                <label htmlFor="exercise">Add an Exercise</label>
                <select name="exercise" id="exercise" onChange={(e)=>value=e.target.value}>
                        <option value="select">--Select Type--</option>
                        <option value="walk">Walking</option>
                        <option value="Jogging">Jogging</option>
                        <option value="skipping">Skipping</option>
                        <option value="yoga">Yoga</option>
                        <option value="sports">Sports</option>
                        <option value="meditation">Meditation</option>
                        <option value="cycling">Cycling</option>
                        <option value="hiking">Hiking</option>
                        <option value="dancing">Dancing</option>
                        <option value="swimming">Swimming</option>
                    </select>
                    <input type="text" id="duration" placeholder="Duration" />
                    <input type="submit" />
                    <button onClick={SelectOption(index={index} ,value={value})}>Add Exercise</button>
            </form>
        </div>
    )
}


function changeExercise(exercise,duration){
    const updated=[...selectedExercise];
    updated.push([exercise,duration]);
    setSelectedExercise(updated);
}
function SelectExercise() {
    
    return(<>
    <h1>Welcome to Exercise Tracking Page</h1>
    <form onSubmit={addExercise}>
        <div className="exerciseContainer">
            <div className="exerciseName">
                <label htmlFor="exercise">Add an Exercise</label>
                    <select name="exercise" id="exercise" onChange={(e)=>value=e.target.value}>
                        <option value="select">--Select Type--</option>
                        <option value="walk">Walking</option>
                        <option value="Jogging">Jogging</option>
                        <option value="skipping">Skipping</option>
                        <option value="yoga">Yoga</option>
                        <option value="sports">Sports</option>
                        <option value="meditation">Meditation</option>
                        <option value="cycling">Cycling</option>
                        <option value="hiking">Hiking</option>
                        <option value="dancing">Dancing</option>
                        <option value="swimming">Swimming</option>
                    </select>
                    
            </div>
            <div className="duration">
                    <input type="text" id="duration" placeholder="Duration" />
            </div>
                <input type="submit" />
        </div>
    </form>
    <button onClick={SelectOption(index={index} ,value={value})}>Add Exercise</button>
    </>   
    );
}

export default SelectExercise;
